{
  "domain_analysis": {
    "business_context": "E-commerce platform managing the full purchase lifecycle: browsing, cart management, checkout with inventory reservation, payment, order fulfillment, and post-delivery refunds. The system enforces inventory integrity, promotion exclusivity, and time-bound reservation and refund windows.",
    "bounded_context": "Order & Checkout",
    "ubiquitous_language": [
      { "term": "Cart", "definition": "A transient collection of items a customer intends to purchase. Items in the cart do not reserve inventory." },
      { "term": "Checkout", "definition": "The process initiated when a customer commits to purchasing cart contents. Triggers inventory reservation." },
      { "term": "Inventory Reservation", "definition": "A time-limited hold on inventory units, created at checkout initiation and released if payment is not completed within 15 minutes." },
      { "term": "Reservation Timeout", "definition": "The 15-minute window from checkout initiation within which payment must be confirmed or the reservation is released." },
      { "term": "Promotion", "definition": "A platform-initiated pricing adjustment applied to a specific product. A product may have at most one active promotion at any time." },
      { "term": "Discount Code", "definition": "A customer-supplied code that reduces order cost. Mutually exclusive with promotional pricing on the same order." },
      { "term": "Payment Confirmation", "definition": "The irreversible event marking an order as paid. After this point, the order becomes immutable." },
      { "term": "Order Immutability", "definition": "The constraint that no modifications (item changes, quantity adjustments, address changes) are permitted after payment is confirmed." },
      { "term": "Refund Window", "definition": "The 30-day period following delivery during which a customer may request a refund." },
      { "term": "Zero Inventory", "definition": "A product state where available stock is zero. Such products may remain listed but cannot be added to a checkout or purchased." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Adding items to a cart does not reserve inventory. Inventory is only reserved when the checkout process begins.",
      "invariant": true,
      "invariant_justification": "Premature reservation would corrupt inventory counts and create phantom holds, leading to data inconsistency between available stock and actual demand.",
      "testable_assertion": "When an item is added to a cart, the product's available inventory count must remain unchanged."
    },
    {
      "id": "BR-2",
      "rule": "An inventory reservation is created at checkout initiation and must be released if payment is not confirmed within 15 minutes.",
      "invariant": false,
      "invariant_justification": "The 15-minute timeout is a business policy parameter that could be adjusted (e.g., to 10 or 20 minutes) without corrupting system state. The mechanism of time-limited reservation is important, but the specific duration is a policy choice.",
      "testable_assertion": "A reservation older than 15 minutes with no corresponding payment confirmation event must be in a 'released' state."
    },
    {
      "id": "BR-3",
      "rule": "A product may have at most one active promotion at any given time.",
      "invariant": true,
      "invariant_justification": "Multiple simultaneous promotions on the same product would create ambiguity in pricing calculations, potentially resulting in incorrect charges. This is a data integrity constraint.",
      "testable_assertion": "For any product at any point in time, querying active promotions must return zero or one result."
    },
    {
      "id": "BR-4",
      "rule": "Discount codes and promotional pricing are mutually exclusive per order. Only one discount mechanism may apply.",
      "invariant": true,
      "invariant_justification": "Allowing both would result in double-discounting, creating incorrect pricing that misrepresents the agreed transaction value. This is a financial integrity constraint.",
      "testable_assertion": "An order's applied discounts must contain either a discount code OR a promotional price, never both simultaneously."
    },
    {
      "id": "BR-5",
      "rule": "An order cannot be modified after payment is confirmed.",
      "invariant": true,
      "invariant_justification": "Post-payment modification would break the financial record of the transaction, potentially causing mismatches between what was charged and what is fulfilled. This is a transactional integrity constraint.",
      "testable_assertion": "Any attempt to modify an order in 'paid' or later status must be rejected with an error."
    },
    {
      "id": "BR-6",
      "rule": "A product with zero available inventory cannot be purchased, regardless of its listing visibility.",
      "invariant": true,
      "invariant_justification": "Selling items that do not exist would create unfulfillable orders, breaking the physical constraint that you cannot ship what you do not have.",
      "testable_assertion": "Checkout initiation for a product with zero available inventory must fail, even if the product page is visible."
    },
    {
      "id": "BR-7",
      "rule": "Refund requests must be submitted within 30 days of the delivery date.",
      "invariant": false,
      "invariant_justification": "The 30-day window is a business policy that could be extended for VIP customers, seasonal adjustments, or regulatory requirements. The concept of a refund window is important, but the specific duration is a policy decision.",
      "testable_assertion": "A refund request submitted more than 30 days after the recorded delivery date must be rejected."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A customer has items in their cart and available inventory exists for those items",
      "when": "The customer initiates checkout",
      "then": "Inventory is reserved for each item in the cart, reducing available inventory by the corresponding quantities"
    },
    {
      "id": "AC-2",
      "given": "A checkout has been initiated and inventory has been reserved",
      "when": "15 minutes elapse without payment confirmation",
      "then": "All inventory reservations for that checkout are released and available inventory is restored"
    },
    {
      "id": "AC-3",
      "given": "A customer has items in their cart",
      "when": "The customer adds an item to the cart",
      "then": "The product's available inventory count remains unchanged (no reservation occurs)"
    },
    {
      "id": "AC-4",
      "given": "A product already has an active promotion",
      "when": "An attempt is made to apply a second promotion to the same product",
      "then": "The system rejects the second promotion, preserving the existing one"
    },
    {
      "id": "AC-5",
      "given": "A customer's order includes a product with an active promotional price",
      "when": "The customer attempts to apply a discount code to the order",
      "then": "The system rejects the discount code and informs the customer that discount codes cannot be combined with promotional pricing"
    },
    {
      "id": "AC-6",
      "given": "A customer's order has a discount code already applied",
      "when": "The customer adds a product with an active promotional price to the order",
      "then": "The system applies only one discount mechanism and clearly communicates which one is in effect"
    },
    {
      "id": "AC-7",
      "given": "An order has reached 'payment confirmed' status",
      "when": "Any attempt is made to modify the order (items, quantities, shipping address, etc.)",
      "then": "The modification is rejected and the order remains unchanged"
    },
    {
      "id": "AC-8",
      "given": "A product is listed on the platform but has zero available inventory",
      "when": "A customer attempts to initiate checkout with that product",
      "then": "The checkout fails with a clear message that the product is out of stock"
    },
    {
      "id": "AC-9",
      "given": "An order was delivered 29 days ago",
      "when": "The customer requests a refund",
      "then": "The refund request is accepted for processing"
    },
    {
      "id": "AC-10",
      "given": "An order was delivered 31 days ago",
      "when": "The customer requests a refund",
      "then": "The refund request is rejected with a message that the 30-day refund window has expired"
    },
    {
      "id": "AC-11",
      "given": "A checkout is in progress with inventory reserved",
      "when": "Payment is confirmed within 15 minutes",
      "then": "The reservation is converted to a committed allocation and the order transitions to a paid/confirmed state"
    },
    {
      "id": "AC-12",
      "given": "Two customers attempt to purchase the last unit of a product simultaneously",
      "when": "Both initiate checkout at the same time",
      "then": "Only one customer successfully reserves the inventory; the other receives an out-of-stock error"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Customer starts checkout, inventory is reserved, then another customer depletes remaining stock through a separate completed purchase before the first customer pays",
      "expected_behavior": "The first customer's reservation is honored because it was created before the stock was depleted. The second customer should have been blocked by the reservation reducing available inventory."
    },
    {
      "scenario": "A product's promotion expires while a customer is in the checkout flow",
      "expected_behavior": "The price at checkout initiation should be locked in for that session. If the promotion expires mid-checkout, the customer should still receive the promotional price for their active checkout."
    },
    {
      "scenario": "Customer applies a discount code, then a promotion is activated on a product in their cart before payment",
      "expected_behavior": "The mutual exclusivity rule applies — the system must resolve which discount mechanism takes precedence and clearly communicate the outcome to the customer."
    },
    {
      "scenario": "Reservation timeout fires at exactly the moment payment confirmation arrives",
      "expected_behavior": "Payment confirmation must take precedence if it arrives at or before the exact timeout boundary. A race condition here could result in a paid order with released inventory — this must be prevented."
    },
    {
      "scenario": "Customer requests a refund on exactly the 30th day after delivery",
      "expected_behavior": "The request should be accepted — the rule states 'within 30 days,' which includes the 30th day itself."
    },
    {
      "scenario": "Product inventory drops to zero after items are already in other customers' carts but before they checkout",
      "expected_behavior": "Since cart does not reserve inventory, those customers will be unable to complete checkout and must be informed the product is now out of stock."
    },
    {
      "scenario": "A discount code is applied to an order, then the customer removes the discounted item and adds a product with a promotion",
      "expected_behavior": "The system must re-evaluate discount eligibility. If only the promoted product remains, the discount code may no longer apply, and the promotional price should take effect."
    },
    {
      "scenario": "Customer abandons checkout, reservation is released, then another customer buys the last unit, then the first customer retries checkout",
      "expected_behavior": "The second checkout attempt fails with an out-of-stock message since inventory is now zero."
    }
  ],

